```cpp
#include <vector>
#include <algorithm>
using namespace std;
struct Item { int value, weight; };
double fractionalKnapsack(vector<Item>& items, int W) {
    sort(items.begin(), items.end(), [](Item a, Item b) { return (double)a.value/a.weight > (double)b.value/b.weight; });
    double total = 0;
    for (auto& item : items) {
        if (W >= item.weight) { total += item.value; W -= item.weight; }
        else { total += (double)item.value * W / item.weight; break; }
    }
    return total;
}
int main() {
    vector<Item> items = {{10,2}, {15,3}, {30,5}};
    cout << fractionalKnapsack(items, 8); // Output: 45
}
```
