3. Huffman Coding:
```cpp
#include <queue>
#include <vector>
using namespace std;
struct Node { char ch; int freq; Node *left, *right; Node(char c, int f) : ch(c), freq(f), left(nullptr), right(nullptr) {} };
Node* huffman(vector<pair<char,int>>& freq) {
    priority_queue<Node*, vector<Node*>, function<bool(Node*,Node*)>> pq([](Node* a, Node* b) { return a->freq > b->freq; });
    for (auto& p : freq) pq.push(new Node(p.first, p.second));
    while (pq.size() > 1) {
        Node *l = pq.top(); pq.pop();
        Node *r = pq.top(); pq.pop();
        Node *n = new Node('$', l->freq + r->freq); n->left = l; n->right = r;
        pq.push(n);
    }
    return pq.top();
}
