struct Job { int id, profit, deadline; };
vector<int> jobSequencing(vector<Job>& jobs) {
    sort(jobs.begin(), jobs.end(), [](Job a, Job b) { return a.profit > b.profit; });
    int maxD = 0;
    for (auto& j : jobs) maxD = max(maxD, j.deadline);
    vector<int> slots(maxD, -1);
    for (auto& j : jobs) {
        for (int i = min(maxD, j.deadline) - 1; i >= 0; i--) {
            if (slots[i] == -1) { slots[i] = j.id; break; }
        }
    }
    return slots;
}
