#include <vector>
#include <queue>
using namespace std;
vector<int> prim(vector<vector<pair<int,int>>>& adj) {
    vector<int> parent(adj.size(), -1);
    vector<bool> inMST(adj.size(), false);
    priority_queue<pair<int,int>, vector<pair<int,int>>, greater<>> pq;
    pq.push({0, 0});
    while (!pq.empty()) {
        int u = pq.top().second; pq.pop();
        if (inMST[u]) continue;
        inMST[u] = true;
        for (auto& [v, w] : adj[u]) {
            if (!inMST[v]) pq.push({w, v});
        }
    }
    return parent;
}
