5. KaratsubaMultiplication:
```cpp
#include <iostream>
using namespace std;
long long karatsuba(long long x, long long y) {
    if (x < 10 || y < 10) return x * y;
    int n = max(to_string(x).size(), to_string(y).size());
    int half = n / 2;
    long long p = pow(10, half);
    long long x1 = x / p, x2 = x % p;
    long long y1 = y / p, y2 = y % p;
    long long p1 = karatsuba(x1, y1);
    long long p2 = karatsuba(x2, y2);
    long long p3 = karatsuba(x1 + x2, y1 + y2);
    return p1 * pow(10, 2 * half) + (p3 - p1 - p2) * p + p2;
}
int main() {
    cout << karatsuba(1234, 5678); // Output: 7006652
}
