```cpp
#include <vector>
#include <algorithm>
#include <iostream>
using namespace std;
struct Point { int x, y; };
Point p0;
long long cross(Point a, Point b, Point c) {
    return (b.x - a.x) * (long long)(c.y - a.y) - (b.y - a.y) * (long long)(c.x - a.x);
}
vector<Point> grahamScan(vector<Point>& points) {
    int n = points.size(), ymin = points[0].y, idx = 0;
    for (int i = 1; i < n; i++)
        if (points[i].y < ymin || (points[i].y == ymin && points[i].x < points[idx].x))
            ymin = points[i].y, idx = i;
    swap(points[0], points[idx]); p0 = points[0];
    sort(points.begin() + 1, points.end(), [](Point a, Point b) {
        long long c = cross(p0, a, b);
        return c > 0 || (c == 0 && (a.x - p0.x) * (a.x - p0.x) + (a.y - p0.y) * (a.y - p0.y) < (b.x - p0.x) * (b.x - p0.x) + (b.y - p0.y) * (b.y - p0.y));
    });
    vector<Point> hull = {points[0]};
    for (int i = 1; i < n; i++) {
        while (hull.size() > 1 && cross(hull[hull.size()-2], hull.back(), points[i]) <= 0)
            hull.pop_back();
        hull.push_back(points[i]);
    }
    return hull;
}
int main() {
    vector<Point> points = {{0,0}, {2,1}, {1,2}, {3,3}};
    auto hull = grahamScan(points);
    for (auto p : hull) cout << p.x << "," << p.y << " "; // Output: 0,0 2,1 3,3 1,2
