#include <iostream>
using namespace std;
struct Point { int x, y; };
bool pointInPolygon(vector<Point>& polygon, Point p) {
    int n = polygon.size(), count = 0;
    for (int i = 0; i < n; i++) {
        Point a = polygon[i], b = polygon[(i + 1) % n];
        if ((a.y <= p.y && b.y > p.y || a.y > p.y && b.y <= p.y) &&
            p.x < a.x + (b.x - a.x) * (p.y - a.y) / (b.y - a.y))
            count++;
    }
    return count % 2 == 1;
}
int main() {
    vector<Point> polygon = {{0,0}, {4,0}, {4,4}, {0,4}};
    Point p = {2,2};
    cout << pointInPolygon(polygon, p); // Output: 1
}
