#include <vector>
#include <iostream>
using namespace std;
struct Point { int x, y; };
double polygonArea(vector<Point>& polygon) {
    long long area = 0;
    int n = polygon.size();
    for (int i = 0; i < n; i++) {
        int j = (i + 1) % n;
        area += polygon[i].x * (long long)polygon[j].y - polygon[j].x * (long long)polygon[i].y;
    }
    return abs(area) / 2.0;
}
int main() {
    vector<Point> polygon = {{0,0}, {4,0}, {0,4}};
    cout << polygonArea(polygon); // Output: 8
}
