1. TSP (Simplified DP):
```cpp
#include <vector>
#include <iostream>
using namespace std;
int tsp(vector<vector<int>>& graph, int pos, int visited, int n, vector<vector<int>>& dp) {
    if (visited == (1 << n) - 1) return graph[pos][0];
    if (dp[pos][visited] != -1) return dp[pos][visited];
    int ans = INT_MAX;
    for (int city = 0; city < n; city++) {
        if (!(visited & (1 << city))) {
            ans = min(ans, graph[pos][city] + tsp(graph, city, visited | (1 << city), n, dp));
        }
    }
    return dp[pos][visited] = ans;
}
int main() {
    vector<vector<int>> graph = {{0,2,3,4}, {2,0,4,1}, {3,4,0,5}, {4,1,5,0}};
    vector<vector<int>> dp(4, vector<int>(1 << 4, -1));
    cout << tsp(graph, 0, 1, 4, dp); // Output: ~13
}
```
2. Knapsack (0/1):
```cpp
#include <vector>
#include <iostream>
using namespace std;
int knapsack(vector<int>& wt, vector<int>& val, int W) {
    int n = wt.size();
    vector<vector<int>> dp(n + 1, vector<int>(W + 1, 0));
    for (int i = 1; i <= n; i++)
        for (int w = 0; w <= W; w++)
            if (wt[i-1] <= w) dp[i][w] = max(val[i-1] + dp[i-1][w-wt[i-1]], dp[i-1][w]);
            else dp[i][w] = dp[i-1][w];
    return dp[n][W];
}
int main() {
    vector<int> val = {10,15}, wt = {2,3};
    cout << knapsack(wt, val, 5); // Output: 25
}
```
