```cpp
#include <vector>
#include <iostream>
using namespace std;
bool isSatisfiable(vector<vector<int>>& clauses, vector<int>& assign, int pos) {
    if (pos == assign.size()) {
        for (auto& clause : clauses) {
            bool satisfied = false;
            for (int lit : clause)
                if ((lit > 0 && assign[lit-1] == 1) || (lit < 0 && assign[-lit-1] == 0))
                    satisfied = true;
            if (!satisfied) return false;
        }
        return true;
    }
    assign[pos] = 0;
    if (isSatisfiable(clauses, assign, pos + 1)) return true;
    assign[pos] = 1;
    if (isSatisfiable(clauses, assign, pos + 1)) return true;
    return false;
}
int main() {
    vector<vector<int>> clauses = {{1,-2}, {-1,3}};
    vector<int> assign(3, 0);
    cout << isSatisfiable(clauses, assign, 0); // Output: 1
}
```
